.02123551,0.07052963,-0.01227294,0.01582650,0.05858321,0.03197010,-0.00481386,-0.01410854,-0.00156930,0.00642096,0.00200262,-0.03256627,-0.00162519,-0.02426945,-0.02745069,0.02157436,-0.05601855,0.03524790,-0.03266146,-0.04474103,0.03497329,-0.03936800,-0.03429005,-0.04448749,-0.03279231,0.01049501,-0.02949701,-0.01605173,0.02950340,-0.02050899,0.02245640,0.01511761,0.04688309,0.02783831,-0.09275635,0.01781607,-0.00184568,-0.03885722,0.12488348,-0.00791480,0.03322801]',E'Example\n\nDependencies:\n\n```toml\n[dependencies]\nactix-web = "4"\n```\n\nCode:\n\n```rust\nuse actix_web::{get, web, App, HttpServer, Responder};\n\n#[get("/hello/{name}")]\nasync fn greet(name: web::Path<String>) -> impl Responder {\n    format!("Hello {name}!")\n}\n\n#[actix_web::main] // or #[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    HttpServer::new(|| {\n        App::new().service(greet)\n    })\n    .bind(("127.0.0.1", 8080))?\n    .run()\n    .await\n}\n```','{"source": "actix-web", "version": "4.13", "language": "rust", "title": "Readme", "section_title": "README", "url": "https://github.com/actix/actix-web/blob/master/actix-web/README.md", "topics": "actix,http,async,README", "categories": "web,rust,rest,async"}');
